import hashlib
import uuid
from datetime import datetime
from typing import Dict, List, Optional, Union
from enum import Enum, auto


class InteractionType(Enum):
    LIKE = auto()
    RATING = auto()
    UPLOAD = auto()
    SETTINGS_CHANGE = auto()


class Interaction:
    def __init__(
        self,
        interaction_type: InteractionType,
        timestamp: datetime,
        metadata: Optional[Dict] = None,
    ):
        self.interaction_type = interaction_type
        self.timestamp = timestamp
        self.metadata = metadata or {}

    def to_dict(self) -> Dict:
        return {
            "interaction_type": self.interaction_type.name,
            "timestamp": self.timestamp.isoformat(),
            "metadata": self.metadata,
        }


class UserInteractionTracker:
    def __init__(self):
        self._user_interactions: Dict[str, List[Interaction]] = {}
        self._salt = uuid.uuid4().hex  # For anonymization

    def _anonymize_user_id(self, user_id: str) -> str:
        """Hashes the user ID for anonymization while preserving uniqueness."""
        return hashlib.sha256((user_id + self._salt).encode()).hexdigest()

    def add_interaction(
        self,
        user_id: str,
        interaction_type: InteractionType,
        metadata: Optional[Dict] = None,
    ) -> None:
        """Records a user interaction with optional metadata."""
        if metadata is None:
            metadata = {}

        # Remove any PII from metadata (example: ensure no emails/names are stored)
        sanitized_metadata = {
            k: v for k, v in metadata.items() if not self._contains_pii(str(v))
        }

        anonymized_id = self._anonymize_user_id(user_id)
        interaction = Interaction(interaction_type, datetime.now(), sanitized_metadata)

        if anonymized_id not in self._user_interactions:
            self._user_interactions[anonymized_id] = []
        self._user_interactions[anonymized_id].append(interaction)

    def get_user_interactions(self, user_id: str) -> List[Dict]:
        """Retrieves all interactions for a user (anonymized)."""
        anonymized_id = self._anonymize_user_id(user_id)
        interactions = self._user_interactions.get(anonymized_id, [])
        return [interaction.to_dict() for interaction in interactions]

    def _contains_pii(self, value: str) -> bool:
        """Basic check for potential PII (can be expanded)."""
        pii_indicators = ["@", "name=", "email=", "address=", "phone="]
        return any(indicator in value.lower() for indicator in pii_indicators)

    def get_all_interactions(self) -> Dict[str, List[Dict]]:
        """Returns all interactions (for debugging/admin purposes)."""
        return {
            user_id: [interaction.to_dict() for interaction in interactions]
            for user_id, interactions in self._user_interactions.items()
        }


# Example usage
if __name__ == "__main__":
    tracker = UserInteractionTracker()

    # Simulate user interactions
    tracker.add_interaction("user123", InteractionType.LIKE, {"item_id": "post_456"})
