import hashlib
import json
from datetime import datetime
from typing import Dict, List, Union, Optional
from abc import ABC, abstractmethod

class Interaction(ABC):
    """Base class for all interaction types."""
    def __init__(self, user_id: str, timestamp: datetime):
        self.user_id = self._anonymize_user_id(user_id)
        self.timestamp = timestamp

    @staticmethod
    def _anonymize_user_id(user_id: str) -> str:
        """Hash user_id for anonymization."""
        return hashlib.sha256(user_id.encode()).hexdigest()

    @abstractmethod
    def to_dict(self) -> Dict:
        """Convert interaction to a dictionary for storage."""
        pass

class LikeInteraction(Interaction):
    """Represents a 'like' interaction."""
    def __init__(self, user_id: str, timestamp: datetime, content_id: str):
        super().__init__(user_id, timestamp)
        self.content_id = content_id

    def to_dict(self) -> Dict:
        return {
            "type": "like",
            "user_id": self.user_id,
            "timestamp": self.timestamp.isoformat(),
            "content_id": self.content_id
        }

class RatingInteraction(Interaction):
    """Represents a 'rating' interaction."""
    def __init__(self, user_id: str, timestamp: datetime, content_id: str, rating: int):
        super().__init__(user_id, timestamp)
        self.content_id = content_id
        self.rating = rating

    def to_dict(self) -> Dict:
        return {
            "type": "rating",
            "user_id": self.user_id,
            "timestamp": self.timestamp.isoformat(),
            "content_id": self.content_id,
            "rating": self.rating
        }

class UploadInteraction(Interaction):
    """Represents an 'upload' interaction."""
    def __init__(self, user_id: str, timestamp: datetime, file_id: str, file_type: str):
        super().__init__(user_id, timestamp)
        self.file_id = file_id
        self.file_type = file_type

    def to_dict(self) -> Dict:
        return {
            "type": "upload",
            "user_id": self.user_id,
            "timestamp": self.timestamp.isoformat(),
            "file_id": self.file_id,
            "file_type": self.file_type
        }

class SettingsChangeInteraction(Interaction):
    """Represents a 'settings change' interaction."""
    def __init__(self, user_id: str, timestamp: datetime, setting_name: str, old_value: str, new_value: str):
        super().__init__(user_id, timestamp)
        self.setting_name = setting_name
        self.old_value = old_value
        self.new_value = new_value

    def to_dict(self) -> Dict:
        return {
            "type": "settings_change",
            "user_id": self.user_id,
            "timestamp": self.timestamp.isoformat(),
            "setting_name": self.setting_name,
            "old_value": self.old_value,
            "new_value": self.new_value
        }

class InteractionTracker:
    """Tracks and manages user interactions."""
    def __init__(self):
        self.interactions: List[Dict] = []

    def add_interaction(self, interaction: Interaction) -> None:
        """Add an interaction to the tracker."""
        self.interactions.append(interaction.to_dict())

    def get_interactions_by_user(self, user_id: str) -> List[Dict]:
        """Retrieve all interactions for a given user (hashed)."""
        hashed_id = Interaction._anonymize_user_id(user_id)
        return [interaction for interaction in self.interactions if interaction["user_id"] == hashed_id]

    def get_interactions_by_type(self, interaction_type: str) -> List[Dict]:
        """Retrieve all interactions of a specific type."""
        return [interaction for interaction in self.interactions if interaction["type"] == interaction_type]

    def save_to_file(self, file_path: str) -> None:
        """Save interactions to a JSON file."""
        with open(file_path, 'w') as f:
            json.dump(self.interactions, f, indent=2)

    def load_from_file(self, file_path: str) -> None:
        """Load interactions from a JSON file."""
        with open(file_path, 'r') as f:
            self.interactions = json.load(f)

# Example usage
if __name__ == "__main__":
    tracker = InteractionTracker()

    # Adding interactions
    tracker.add_interaction(LikeInteraction("user123", datetime.now(), "content456"))
    tracker.add_interaction(RatingInteraction("user123", datetime.now(), "content789", 5))
    tracker.add_interaction(UploadInteraction("user456", datetime.now(), "file123", "image/png"))
    tracker.add_interaction(SettingsChangeInteraction("user456", datetime.now(), "theme", "light", "dark"))

    # Save to file
    tracker.save_to_file("interactions.json")

    # Load from file
    new_tracker = InteractionTracker()
    new_tracker.load_from_file("interactions.json")

    # Query interactions
    print(new_tracker.get_interactions_by_user("user123"))
    print(new_tracker.get_interactions_by_type("upload"))

