            salt = str(uuid4())
            hashed = hashlib.sha256((user_id + salt).encode()).hexdigest()
            self.user_anonymizer[user_id] = hashed
        return self.user_anonymizer[user_id]

    def _validate_like(self, data: Dict) -> bool:
        required = ['content_id', 'action']
        return all(key in data for key in required) and data['action'] in ['like', 'unlike']

    def _validate_rating(self, data: Dict) -> bool:
        return 'content_id' in data and 'value' in data and 1 <= data['value'] <= 5

    def _validate_upload(self, data: Dict) -> bool:
        return 'content_type' in data and 'size_kb' in data and data['size_kb'] > 0

    def _validate_settings_change(self, data: Dict) -> bool:
        return 'setting_name' in data and 'new_value' in data

    def _validate_interaction(self, interaction_type: str, data: Dict) -> bool:
        if interaction_type not in self.interaction_types:
            return False
        return self.interaction_types[interaction_type](data)

    def log_interaction(self, user_id: str, interaction_type: str, data: Dict) -> bool:
