        self,
        engagement_type: EngagementType,
        user_id: str,
        metadata: Optional[Dict[str, Union[str, int, float]]] = None
    ) -> None:
        if not isinstance(engagement_type, EngagementType):
            raise ValueError("Invalid engagement type")

        sanitized_metadata = self._sanitize_metadata(metadata) if metadata else None
        user_id_hash = self._anonymize_user_id(user_id)

        event = EngagementEvent(
            engagement_type=engagement_type,
            timestamp=datetime.now(),
            user_id_hash=user_id_hash,
            metadata=sanitized_metadata
        )

        self.engagement_log[engagement_type].append(event)

