    LIKE = auto()
    RATING = auto()
    UPLOAD = auto()
    SETTINGS_ADJUSTMENT = auto()

@dataclass
class Engagement:
    engagement_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    user_id: str
    engagement_type: EngagementType
    timestamp: datetime = field(default_factory=datetime.now)
    metadata: Dict[str, Union[str, int, float]] = field(default_factory=dict)

    def __post_init__(self):
        self.user_id = self._anonymize_user_id(self.user_id)
        self._validate_metadata()

    def _anonymize_user_id(self, user_id: str) -> str:
        return hashlib.sha256(user_id.encode()).hexdigest()

    def _validate_metadata(self):
        prohibited_keys = ['password', 'credit_card', 'ssn']
        for key in prohibited_keys:
            if key in self.metadata:
                raise ValueError(f"Illegal metadata key detected: {key}")

class EngagementMonitor:
    def __init__(self):
        self.engagements: Dict[str, List[Engagement]] = {}

    def log_engagement(self, engagement: Engagement) -> None:
        if engagement.user_id not in self.engagements:
            self.engagements[engagement.user_id] = []
        self.engagements[engagement.user_id].append(engagement)

    def get_user_engagements(self, user_id: str) -> List[Engagement]:
        anonymized_id = hashlib.sha256(user_id.encode()).hexdigest()
        return self.engagements.get(anonymized_id, [])

    def get_engagements_by_type(self, engagement_type: EngagementType) -> List[Engagement]:
        result = []
        for engagements in self.engagements.values():
            result.extend([e for e in engagements if e.engagement_type == engagement_type])
        return result

    def clear_engagements(self) -> None:
        self.engagements.clear()

    def add_new_engagement_type(self, new_type: str) -> EngagementType:
        if new_type in EngagementType.__members__:
            return EngagementType[new_type]
        new_enum_value = auto()
        EngagementType._member_map_[new_type] = new_enum_value
        EngagementType._value2member_map_[new_enum_value.value] = new_enum_value
        return new_enum_value

