    def log_activity(self, user_id: str, activity_type: str, details: Dict = None) -> None:
        """Log a user activity with hashed user ID and timestamp."""
        if details is None:
            details = {}

        hashed_id = self._hash_user_id(user_id)
        activity = {
            'activity_id': self._generate_activity_id(),
            'timestamp': datetime.utcnow().isoformat(),
            'type': activity_type,
            'details': details
        }

        if hashed_id not in self.activities:
            self.activities[hashed_id] = []
        self.activities[hashed_id].append(activity)

    def get_user_activities(self, user_id: str) -> List[Dict]:
        """Retrieve activities for a user (hashed ID)."""
        hashed_id = self._hash_user_id(user_id)
        return self.activities.get(hashed_id, [])

    def get_all_activities(self) -> Dict[str, List[Dict]]:
        """Retrieve all activities (for admin purposes)."""
        return self.activities

    def clear_user_activities(self, user_id: str) -> None:
        """Clear all activities for a user."""
        hashed_id = self._hash_user_id(user_id)
        if hashed_id in self.activities:
            del self.activities[hashed_id]

